mapper.select:
SELECT *
FROM agent_coach_nudge
WHERE id = #{id}
  AND user_id = #{userId}
LIMIT 1

SELECT *
FROM agent_coach_nudge
WHERE user_id = #{userId}
  AND trigger_source = #{triggerSource}
  AND action_type = #{actionType}
  AND created_at > #{after}
  AND status IN ('ACTIVE', 'CLICKED', 'DISMISSED', 'SNOOZED')
ORDER BY created_at DESC

mapper.update:
UPDATE agent_coach_nudge
SET status = #{status},
    updated_at = #{updatedAt},
    expires_at = #{expiresAt}
WHERE id = #{id}
  AND user_id = #{userId}
